from src.nodes.base import BaseNode

async def execute(self, inputs):
    name = inputs.get('dict_name') or self.get_parameter('dict_name', '')
    entries = inputs.get('entries')
    if entries is None:
        entries = self.get_parameter('entries', {})
    try:
        d = dict(entries) if entries is not None else {}
    except Exception:
        d = {}

    stored = False
    if name:
        BaseNode.memory[name] = d
        stored = True
        self.log_info(f'Stored dict {name} with {len(d)} entries')
    else:
        self.log_info(f'Created dict with {len(d)} entries (not stored)')

    await self.set_output('current_dict', d)
    await self.set_output('stored', stored)
    await self.set_output('exec_out', True)
    return {'current_dict': d, 'stored': stored}
